const baseMarketValue = Math.max(0, inputs.baseMarketValue); 
const socialMediaReach = Math.max(0, inputs.socialMediaReach); 
const audienceEngagementRate = Math.max(0, inputs.audienceEngagementRate); 
const philanthropicInvolvementScore = Math.min(10, Math.max(1, inputs.philanthropicInvolvementScore)); 
const publicPerceptionIndex = Math.min(10, Math.max(1, inputs.publicPerceptionIndex)); 
const ethicalAlignmentScore = Math.min(10, Math.max(1, inputs.ethicalAlignmentScore)); 
const controversySeverityScore = Math.min(10, Math.max(0, inputs.controversySeverityScore)); 
const brandEthicalMatch = Math.min(10, Math.max(1, inputs.brandEthicalMatch)); 

// 1. Calculate the Positive Impact Factor (PIF)
const pifScoreRaw = (
    philanthropicInvolvementScore * 0.20 +
    publicPerceptionIndex * 0.30 +
    ethicalAlignmentScore * 0.30 +
    brandEthicalMatch * 0.20
);
const socialImpactScore = Math.min(10, Math.max(1, pifScoreRaw));
const pifMultiplier = 1 + (socialImpactScore / 10) * 0.6; // Max 60% uplift for perfect social impact

// 2. Calculate Social Reach Value Add (SRVA)
const engagementFactor = audienceEngagementRate;
const socialReachValueAdd = (socialMediaReach / 1000000) * engagementFactor * 8000000;
// Cap SRVA to prevent disproportionate influence from mega-influencers beyond core value
const maxSrva = baseMarketValue * 0.8;
const cappedSrva = Math.min(socialReachValueAdd, maxSrva);

// 3. Calculate Negative Impact Factor (NIF)
const controversyImpact = controversySeverityScore / 10; // Normalized to 0-1
let nifMultiplier = 1 - (controversyImpact * 0.9); // Max 90% deduction for severe controversy
nifMultiplier = Math.max(0.05, nifMultiplier); // Floor at 5% of potential value for extreme cases

// 4. Calculate Intermediate Value before final negative impact application
const intermediateValue = (baseMarketValue * pifMultiplier) + cappedSrva;

// 5. Apply Negative Impact and Final Calculation
let calculatedEndorsementValue = intermediateValue * nifMultiplier;

// Final Cap and Floor for realism
const maxPossibleEndorsementValue = baseMarketValue * 3.5; // Cap at 3.5x base market value (e.g., if base is $1M, max is $3.5M)
const minPossibleEndorsementValue = baseMarketValue * 0.01; // Minimum floor (1% of base)

calculatedEndorsementValue = Math.min(maxPossibleEndorsementValue, Math.max(minPossibleEndorsementValue, calculatedEndorsementValue));

return {
    calculatedEndorsementValue: calculatedEndorsementValue,
    socialImpactScore: socialImpactScore
};
